def test_fifth_pin_change_succeeds_sixth_rejected(api_client, reset_pin_rate_limit):
    card_id = <fixture:owned_card_id>
    for i in range(5):
        resp = api_client.patch(
            f"/cards/{card_id}/pin",
            json={"pin": <helper_fn:generate_valid_pin>(seed=i)}
        )
        assert resp.status_code in (200, 204), f"Change {i+1} failed: {resp.status_code}"
    resp_over = api_client.patch(
        f"/cards/{card_id}/pin",
        json={"pin": <helper_fn:generate_valid_pin>(seed=99)}
    )
    assert resp_over.status_code == 429, f"Expected 429, got {resp_over.status_code}"
    body = resp_over.json()
    assert "rate" in body.get("error", "").lower() or body.get("code") == "RATE_LIMIT_EXCEEDED"

def test_pin_change_rejected_when_limit_already_exhausted(api_client, exhausted_pin_rate_limit):
    card_id = <fixture:owned_card_id>
    resp = api_client.patch(
        f"/cards/{card_id}/pin",
        json={"pin": <helper_fn:generate_valid_pin>()}
    )
    assert resp.status_code == 429, f"Expected 429, got {resp.status_code}"
    assert "Retry-After" in resp.headers or "retry_after" in resp.json()

def test_pin_change_rejected_for_unowned_card(api_client, reset_pin_rate_limit):
    foreign_card_id = <fixture:foreign_card_id>
    resp = api_client.patch(
        f"/cards/{foreign_card_id}/pin",
        json={"pin": <helper_fn:generate_valid_pin>()}
    )
    assert resp.status_code in (403, 404), (
        f"Expected 403 or 404 for unowned card, got {resp.status_code}"
    )
    audit = <helper_fn:get_audit_as_admin>(foreign_card_id)
    assert audit["count_last_24h"] == 0, "Rate-limit counter must not increment on auth failure"
